# phytron.proto
# StreamDevice protocol definitions for Phytron MCC-1 MINI-W-ETH
# TCP communication target port: 22222
#
# Notes:
# - Command/response syntax for this device may need adjustment once verified
#   against the vendor command manual or live controller traces.
# - This scaffold is intentionally simple and easy to debug.

Terminator = CR LF;
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
LockTimeout = 5000;
ExtraInput = Ignore;

# Read current position readback
getPosition {
    out "POS?";
    in "%f";
}

# Read configured/actual speed readback
getSpeed {
    out "SPEED?";
    in "%f";
}

# Jog / move in positive direction
movePlus {
    out "MOVE_PLUS";
}

# Jog / move in negative direction
moveMinus {
    out "MOVE_MINUS";
}

# Stop motion
stopMotion {
    out "STOP";
}
